import java.io.IOException;

public class ImageConverter {

    public static void convertImage(String inputFilename, String outputFilename, String format) {
        try {
            String[] command = {"convert", inputFilename, "-format", format, outputFilename};
            Process process = Runtime.getRuntime().exec(command);
            int exitCode = process.waitFor();
            if (exitCode == 0) {
                System.out.println("Image converted successfully.");
            } else {
                System.err.println("Failed to convert image. Exit code: " + exitCode);
            }
        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }

    public static void main(String[] args) {
        // Example usage
        convertImage("input.jpg", "output.png", "png");
    }
}